  function setFieldError(id, message){
    const el=$(id);
    if(!el) return;
    el.classList.add('invalidField');
    el.setAttribute('aria-invalid','true');
    const msg=document.createElement('div');
    msg.className='fieldError';
    msg.textContent=message;
    const parent=el.parentElement || el;
    parent.appendChild(msg);
  }
  function requireField(errors, id, message){
    if(!fieldText(id)) errors.push({id,message});
  }
  function requireValidDate(errors, id, message){
    const value = fieldText(id);
    if(value && !formatISODate(value)) errors.push({id,message});
  }
  function validateBeforePdf(plan){
    clearValidation();

    if(appointmentMode === 'zoom'){
      var zoomErrors = [];
      if(!plan.totalPages){
        var e = new Error('No output pages selected. Enable at least one output option in Appointment Outputs.');
        e.isValidation = true; throw e;
      }
      requireField(zoomErrors,'date','Enter the appointment date.');
      requireField(zoomErrors,'teamMember','Enter the staff member.');
      requireField(zoomErrors,'clientName','Enter the client name.');
      zoomErrors.filter(function(e){return e.id;}).forEach(function(e){setFieldError(e.id,e.message);});
      if(zoomErrors.length){
        var f=zoomErrors[0];
        if(f.id && $(f.id)) $(f.id).scrollIntoView({behavior:'smooth',block:'center'});
        var ve = new Error(zoomErrors.map(function(e){return e.message;}).join(' '));
        ve.isValidation = true; throw ve;
      }
      return;
    }
    const errors=[];
    if(!plan.totalPages){
      errors.push({id:null,message:'Select an IA form, include the EOI form, and/or attach at least one ID image.'});
    }
    requireField(errors,'date','Enter the appointment date.');
    requireValidDate(errors,'date','Enter the appointment date as DD/MM/YYYY.');
    requireField(errors,'teamMember','Enter the staff member.');
    requireField(errors,'clientName','Enter the client name.');

    if (plan.includeEOI) {
      requireValidDate(errors,'eoiDate','Enter the EOI date as DD/MM/YYYY.');
      requireValidDate(errors,'eoiNextApptDate','Enter the next appointment date as DD/MM/YYYY.');
      if (!eoiSaleAddressValue()) {
        const showEoiOverrides = isChecked('showEoiOverrides');
        errors.push({id: showEoiOverrides ? 'eoiSaleAddress' : 'propertySaleAddress', message:'Enter the property sale address.'});
      }
    }
    if (plan.selectedIA) {
      requireValidDate(errors,'iaDate','Enter the IA date as DD/MM/YYYY.');
      const showIaOverrides = isChecked('showIaOverrides');
      const resolvedIaNames = showIaOverrides ? (fieldText('iaClientNames') || mergedClientNames()) : mergedClientNames();
      const resolvedIaAddress = resolvedIaField('iaAddress', 'clientAddress');
      const resolvedIaProperty = resolvedIaField('iaProperty', 'propertySaleAddress');

      if (!resolvedIaNames) {
        errors.push({id: showIaOverrides ? 'iaClientNames' : 'clientName', message:'Enter the client name.'});
      }
      if (!resolvedIaAddress) {
        errors.push({id: showIaOverrides ? 'iaAddress' : 'clientAddress', message:'Enter the client address.'});
      }
      if (!resolvedIaProperty) {
        errors.push({id: showIaOverrides ? 'iaProperty' : 'propertySaleAddress', message:'Enter the property sold address.'});
      }
    }

    errors.filter(err=>err.id).forEach(err=>setFieldError(err.id,err.message));
    if(errors.length){
      const first=errors[0];
      if(first.id && $(first.id)) $(first.id).scrollIntoView({behavior:'smooth',block:'center'});
      const validationError = new Error(errors.map(err=>err.message).join(' '));
      validationError.isValidation = true;
      throw validationError;
    }
  }
  function safePart(s, fallback){
    s = (s || '').trim() || fallback;
    return s.replace(/[\\/:*?"<>|]+/g,'').replace(/\s+/g,' ').slice(0,80);
  }
  function pdfFileName(){
    if(appointmentMode === 'zoom') return zoomPdfFileName();
    try {
      const dateVal = $('date') ? $('date').value : '';
      const date = dateVal ? formatDisplayDate(dateVal).replace(/\//g, '-') : 'DD-MM-YYYY';
      const team = safePart($('teamMember') ? $('teamMember').value : '', 'TeamMember');
      const c1 = safePart($('clientName') ? $('clientName').value : '', '');
      const c2 = safePart($('client2Name') ? $('client2Name').value : '', '');
      // Always include Client 1 if present. Append Client 2 if present and fits.
      let client = c1 || 'ClientName';
      if (c2 && c1 && (c1.length + c2.length + 3) <= 80){
        client = `${c1} & ${c2}`;
      }
      return `Sales Appointment - ${date} - ${client} - ${team}.pdf`;
    } catch (e) {
      console.error('pdfFileName failed:', e);
      return `Sales Appointment - ${new Date().toISOString().slice(0,10)}.pdf`;
    }
  }
  function clientNamesForFilename(){
    const c1 = safePart(fieldText('clientName'), '');
    const c2 = safePart(fieldText('client2Name'), '');
    if (c1 && c2 && (c1.length + c2.length + 3) <= 80) return `${c1} & ${c2}`;
    return c1 || 'Client';
  }
  function zipFileName(){
    if(appointmentMode === 'zoom'){
      const clientNames = clientNamesForFilename();
      const dateVal = $('date') ? $('date').value : '';
      const date = dateVal ? formatDisplayDate(dateVal).replace(/\//g, '-') : 'DD-MM-YYYY';
      return clientNames + ' - Zoom Appointment Documents - ' + date + '.zip';
    }
    const clientNames = clientNamesForFilename();
    const dateVal = $('date') ? $('date').value : '';
    const date = dateVal ? formatDisplayDate(dateVal).replace(/\//g, '-') : 'DD-MM-YYYY';
    return `${clientNames} - Separated Appointment Documents - ${date}.zip`;
  }
