  function updateSummaryCard(){
    /* Show/hide in-person vs zoom summary */
    var isZoom = appointmentMode === 'zoom';
    var inPersonBody = document.querySelector('.summary-card-body:not(#zoomSummaryBody)');
    var zoomBody = $('zoomSummaryBody');
    if(inPersonBody) inPersonBody.style.display = isZoom ? 'none' : '';
    if(zoomBody) zoomBody.style.display = isZoom ? 'flex' : 'none';

    /* Zoom summary indicators */
    if(isZoom && zoomBody){
      $('zoomSumStaff').textContent = fieldText('teamMember') || 'Staff';
      $('zoomSumClient1').textContent = fieldText('clientName') || 'Client 1';
      $('zoomSumClient2').textContent = fieldText('client2Name') || 'Client 2';
      $('zoomSumBuilder').textContent = fieldText('clientReviewBuilder') || 'Builder';
      $('zoomSumDeveloper').textContent = fieldText('clientReviewDeveloper') || 'Developer';
      $('zoomSumBroker').textContent = fieldText('clientReviewBroker') || 'Broker';
      $('zoomSumConveyancer').textContent = fieldText('clientReviewConveyancer') || 'Conveyancer';
      $('zoomSumProperty').textContent = fieldText('clientReviewProperty') || 'Property';
      $('zoomSumEOI').textContent = (isChecked('zoomIncludeStandardEOI') || isChecked('zoomIncludeLaVidaEOI')) ? 'EOI Selected' : 'Not Selected';
      $('zoomSumIA').textContent = isChecked('zoomIncludeIA') ? 'IA Selected' : 'Not Selected';
      updateIndicator('indicator-zoomStaff', !!fieldText('teamMember'));
      updateIndicator('indicator-zoomClient1', !!fieldText('clientName'));
      updateIndicator('indicator-zoomClient2', !!fieldText('client2Name'));
      updateIndicator('indicator-zoomBuilder', !!fieldText('clientReviewBuilder'));
      updateIndicator('indicator-zoomDeveloper', !!fieldText('clientReviewDeveloper'));
      updateIndicator('indicator-zoomBroker', !!fieldText('clientReviewBroker'));
      updateIndicator('indicator-zoomConveyancer', !!fieldText('clientReviewConveyancer'));
      updateIndicator('indicator-zoomProperty', !!fieldText('clientReviewProperty'));
      updateIndicator('indicator-zoomEOI', isChecked('zoomIncludeStandardEOI') || isChecked('zoomIncludeLaVidaEOI'));
      updateIndicator('indicator-zoomIA', isChecked('zoomIncludeIA'));
    /* Show PDF ready status */
    const zoomStatusEl = $('appointmentStatus');
    if(zoomStatusEl){
      if(lastPdfBlob && appointmentMode === 'zoom'){
        zoomStatusEl.textContent = '\u2705 Zoom booklet ready';
        zoomStatusEl.style.color = 'var(--success)';
      }
    }
    }

    const hasC2 = hasClient2();
    const _hasC1Photo = hasC1Photo();
    const _hasC2Photo = hasC2Photo();

    // Individual field indicators
    updateIndicator('indicator-clientName', !!fieldText('clientName'));
    updateIndicator('indicator-clientPhone', !!fieldText('clientPhone'));
    updateIndicator('indicator-clientEmail', !!fieldText('clientEmail'));

    updateIndicator('indicator-client2Name', !!fieldText('client2Name'));
    updateIndicator('indicator-client2Phone', !!fieldText('client2Phone'));
    updateIndicator('indicator-client2Email', !!fieldText('client2Email'));

    updateIndicator('indicator-clientAddress', !!fieldText('clientAddress'));
    updateIndicator('indicator-propertySaleAddress', !!fieldText('propertySaleAddress'));

    updateIndicator('indicator-includeEOI', isChecked('includeEOI'));
    updateIndicator('indicator-includeIA', isChecked('includeIA'));

    // Live counts and color coding for Photos
    const totalPossiblePhotos = photos.length;
    const uploadedCount = photos.filter(p => p.img).length;
    const labelPhotos = $('label-photos');
    if (labelPhotos) {
      labelPhotos.textContent = `${uploadedCount} / ${totalPossiblePhotos} Uploaded`;
      if (uploadedCount === 0) {
        labelPhotos.style.color = 'var(--muted)';
      } else if (uploadedCount < totalPossiblePhotos) {
        labelPhotos.style.color = 'var(--gold)';
      } else {
        labelPhotos.style.color = 'var(--success)';
      }
    }

    // Live counts and color coding for Signatures
    const sigsCount = (hasSignature ? 1 : 0) + (hasSignature2 ? 1 : 0);
    const labelSignatures = $('label-signatures');
    if (labelSignatures) {
      labelSignatures.textContent = `${sigsCount} / 2 Captured`;
      if (sigsCount === 0) {
        labelSignatures.style.color = 'var(--muted)';
      } else if (sigsCount === 1) {
        labelSignatures.style.color = 'var(--gold)';
      } else {
        labelSignatures.style.color = 'var(--success)';
      }
    }

    // Calculate missing required items
    let missingRequired = [];

    if (!fieldText('clientName')) missingRequired.push('Client 1 Name');
    if (!fieldText('clientPhone')) missingRequired.push('Client 1 Contact Number');
    if (!fieldText('clientAddress')) missingRequired.push('Client Current Address');
    if (!fieldText('propertySaleAddress')) missingRequired.push('Address of Property Sale');

    const includeEOI = isChecked('includeEOI');
    if (includeEOI) {
      const showEoiOverrides = isChecked('showEoiOverrides');
      if (showEoiOverrides && !fieldText('eoiSaleAddress')) {
        missingRequired.push('EOI Sale Address');
      }
    }

    const includeIA = isChecked('includeIA');
    if (includeIA) {
      const showIaOverrides = isChecked('showIaOverrides');
      if (showIaOverrides) {
        if (!fieldText('iaClientNames')) missingRequired.push('IA Client Name(s)');
        if (!fieldText('iaAddress')) missingRequired.push('IA Client Address');
        if (!fieldText('iaProperty')) missingRequired.push('IA Property Sold Address');
      }
    }

    if (!_hasC1Photo) missingRequired.push('Client 1 ID Photo');
    if (!hasSignature) missingRequired.push('Signature 1');

    if (hasC2) {
      if (!_hasC2Photo) missingRequired.push('Client 2 ID Photo');
      if (!hasSignature2) missingRequired.push('Signature 2');
    }

    const missingCount = missingRequired.length;
    const statusEl = $('appointmentStatus');
    if (statusEl) {
      if (missingCount === 0) {
        statusEl.textContent = '🟢 Ready for PDF';
        statusEl.style.color = 'var(--success)';
      } else {
        statusEl.textContent = `🟠 ${missingCount} Item${missingCount > 1 ? 's' : ''} Remaining`;
        statusEl.style.color = 'var(--gold)';
      }
    }
  }

  function updatePackagePreview(){
    var container = $('packagePreviewContent');
    if(!container) return;
    var plan = appointmentMode === 'zoom' ? zoomOutputPlan() : outputPlan();
    if(!plan || !plan.groups || plan.groups.length === 0){
      container.innerHTML = '<p class="preview-placeholder">Fill in the form to see a live preview of your package.</p>';
      return;
    }
    var labels = {
      cover:'Cover Page', firstConsult:'First Consultation', clientReview:'Client Review / Assessment',
      eoi:'Standard EOI', 'eoi-laVida':'La Vida EOI', ia:'IA',
      client1_front:'Client 1 – Front ID', client1_back:'Client 1 – Back ID',
      client2_front:'Client 2 – Front ID', client2_back:'Client 2 – Back ID'
    };
    var html = '<div class="preview-table">';
    plan.groups.forEach(function(g){
      var label = labels[g.id] || g.id.replace(/_/g,' ');
      var pages = g.pageCount + ' page' + (g.pageCount !== 1 ? 's' : '');
      html += '<div class="preview-row"><span class="preview-label">' + label + '</span><span class="preview-pages">' + pages + '</span></div>';
    });
    html += '<div class="preview-row preview-total"><span class="preview-label">Total</span><span class="preview-pages">' + plan.totalPages + ' page' + (plan.totalPages !== 1 ? 's' : '') + '</span></div>';
    html += '<div class="preview-row preview-zip"><span class="preview-label">Estimated ZIP contents</span><span class="preview-pages">' + plan.groups.length + ' separated file' + (plan.groups.length !== 1 ? 's' : '') + '</span></div>';
    html += '</div>';
    container.innerHTML = html;
  }

  document.querySelectorAll('.summary-card-item').forEach(item => {
    item.addEventListener('click', () => {
      const targetId = item.getAttribute('data-target');
      const targetEl = $(targetId);
      if (targetEl) {
        targetEl.scrollIntoView({ behavior: 'smooth', block: 'center' });
        targetEl.classList.add('field-highlight');
        setTimeout(() => {
          targetEl.classList.remove('field-highlight');
        }, 1500);
        if (targetEl.tagName === 'INPUT' || targetEl.tagName === 'SELECT' || targetEl.tagName === 'TEXTAREA') {
          targetEl.focus();
        }
      }
    });
  });

