  // =========================================================================
  // SECTION G: LIVE SUMMARY RENDERING
  // =========================================================================
  function renderLiveSummary() {
    const liveSummary = $('liveSummary');
    const previewPaper = $('previewPaper');

    if (lastPdfBlob) {
      if (liveSummary) liveSummary.style.display = 'none';
      if (previewPaper) previewPaper.style.display = 'block';
      return;
    }

    if (liveSummary) liveSummary.style.display = 'block';
    if (previewPaper) previewPaper.style.display = 'none';

    /* In zoom mode, skip in-person-specific live summary checks */
    if (appointmentMode === 'zoom') {
      // Only show basic client info
      const c1Name = fieldText('clientName');
      const sumC1 = $('sumClient1');
      if (sumC1) {
        sumC1.textContent = c1Name || 'Missing client name';
        sumC1.style.color = c1Name ? 'var(--navy)' : 'var(--danger)';
      }
      const c2Name = fieldText('client2Name');
      const sumC2 = $('sumClient2');
      const sumC2Row = $('sumClient2Row');
      if (sumC2Row) {
        if (c2Name) {
          sumC2Row.style.display = 'flex';
          if (sumC2) { sumC2.textContent = c2Name; sumC2.style.color = 'var(--navy)'; }
        } else {
          sumC2Row.style.display = 'none';
        }
      }
      const sumMissingSection = $('sumMissingSection');
      const sumMissingList = $('sumMissingList');
      if (sumMissingSection && sumMissingList) {
        const missing = [];
        if (!fieldText('date')) missing.push('Appointment Date');
        if (!fieldText('teamMember')) missing.push('Staff Member / Team Member');
        if (!c1Name) missing.push('Client 1 Name');
        if (missing.length > 0) {
          sumMissingSection.style.display = 'block';
          sumMissingList.innerHTML = missing.map(m => '<li>' + m + '</li>').join('');
        } else {
          sumMissingSection.style.display = 'none';
          sumMissingList.innerHTML = '';
        }
      }
      return;
    }

    // Client 1 Name
    const c1Name = fieldText('clientName');
    const sumC1 = $('sumClient1');
    if (sumC1) {
      sumC1.textContent = c1Name || 'Missing client name';
      sumC1.style.color = c1Name ? 'var(--navy)' : 'var(--danger)';
    }

    // Client 2 Name
    const c2Name = fieldText('client2Name');
    const sumC2 = $('sumClient2');
    const sumC2Row = $('sumClient2Row');
    if (sumC2Row) {
      if (c2Name) {
        sumC2Row.style.display = 'flex';
        if (sumC2) {
          sumC2.textContent = c2Name;
          sumC2.style.color = 'var(--navy)';
        }
      } else {
        sumC2Row.style.display = 'none';
      }
    }

    // EOI
    const includeEOI = isChecked('includeEOI');
    const sumEOI = $('sumEOI');
    if (sumEOI) {
      if (includeEOI) {
        const eoiAddr = eoiSaleAddressValue();
        sumEOI.textContent = eoiAddr ? `Yes (${eoiAddr})` : 'Yes (Missing Sale Address)';
        sumEOI.style.color = eoiAddr ? 'var(--success)' : 'var(--danger)';
      } else {
        sumEOI.textContent = 'Not Included';
        sumEOI.style.color = 'var(--muted)';
      }
    }

    // IA
    const includeIA = isChecked('includeIA');
    const sumIA = $('sumIA');
    if (sumIA) {
      if (includeIA) {
        const iaFormVal = $('iaForm') ? $('iaForm').value : '';
        const defaultIaProperty = fieldText('propertySaleAddress');
        const showIaOverrides = isChecked('showIaOverrides');
        const resolvedIaProperty = showIaOverrides ? (fieldText('iaProperty') || defaultIaProperty) : defaultIaProperty;
        sumIA.textContent = `${iaFormVal.toUpperCase()} (${resolvedIaProperty || 'Missing Property'})`;
        sumIA.style.color = resolvedIaProperty ? 'var(--success)' : 'var(--danger)';
      } else {
        sumIA.textContent = 'Not Included';
        sumIA.style.color = 'var(--muted)';
      }
    }

    // ID Photos Upload
    const uploadedPhotosCount = photos.filter(p => p.img).length;
    const standardUploadedCount = photos.slice(0,4).filter(p => p.img).length;
    const additionalUploadedCount = photos.slice(4).filter(p => p.img).length;
    const sumIDCount = $('sumIDCount');
    if (sumIDCount) {
      sumIDCount.textContent = `${uploadedPhotosCount} uploaded (${standardUploadedCount} standard ID, ${additionalUploadedCount} additional)`;
      sumIDCount.style.color = uploadedPhotosCount > 0 ? 'var(--navy)' : 'var(--muted)';
    }

    // Checklist
    const checkedCount = [1, 2, 3, 4].filter(i => $(`item${i}`) && $(`item${i}`).checked).length;
    const sumChecklistCount = $('sumChecklistCount');
    if (sumChecklistCount) {
      sumChecklistCount.textContent = `${checkedCount} of 4 checked`;
      sumChecklistCount.style.color = checkedCount === 4 ? 'var(--success)' : 'var(--navy)';
    }

    // Signatures
    const sumSig1 = $('sumSig1');
    if (sumSig1) {
      sumSig1.textContent = hasSignature ? '✓ Captured' : 'Missing';
      sumSig1.style.color = hasSignature ? 'var(--success)' : 'var(--danger)';
    }

    const sumSig2 = $('sumSig2');
    if (sumSig2) {
      const hasC2 = c2Name.length > 0;
      if (hasSignature2) {
        sumSig2.textContent = '✓ Captured';
        sumSig2.style.color = 'var(--success)';
      } else {
        if (hasC2) {
          sumSig2.textContent = 'Missing';
          sumSig2.style.color = 'var(--danger)';
        } else {
          sumSig2.textContent = 'Not Required';
          sumSig2.style.color = 'var(--muted)';
        }
      }
    }

    // Missing required items
    const missing = [];
    if (!fieldText('date')) missing.push('Appointment Date');
    if (!fieldText('teamMember')) missing.push('Staff Member / Team Member');
    if (!c1Name) missing.push('Client 1 Name');

    if (includeEOI) {
      if (!eoiSaleAddressValue()) missing.push('EOI Sale Address');
    }

    if (includeIA) {
      const showIaOverrides = isChecked('showIaOverrides');
      const resolvedIaNames = showIaOverrides ? (fieldText('iaClientNames') || mergedClientNames()) : mergedClientNames();
      const resolvedIaAddress = resolvedIaField('iaAddress', 'clientAddress');
      const resolvedIaProperty = resolvedIaField('iaProperty', 'propertySaleAddress');

      if (!resolvedIaNames) missing.push('IA Client Name(s)');
      if (!resolvedIaAddress) missing.push('IA Client Address');
      if (!resolvedIaProperty) missing.push('IA Property Sold Address');
    }

    const hasC2 = c2Name.length > 0;
    const _hasC1Photo = hasC1Photo();
    if (!_hasC1Photo) missing.push('Client 1 ID photo (Front or Back)');
    if (hasC2) {
      const _hasC2Photo = hasC2Photo();
      if (!_hasC2Photo) missing.push('Client 2 ID photo (Front or Back)');
    }

    if (!hasSignature) missing.push('Signature 1');
    if (hasC2 && !hasSignature2) missing.push('Signature 2');

    const sumMissingSection = $('sumMissingSection');
    const sumMissingList = $('sumMissingList');
    if (sumMissingSection && sumMissingList) {
      if (missing.length > 0) {
        sumMissingSection.style.display = 'block';
        sumMissingList.innerHTML = missing.map(m => `<li>${m}</li>`).join('');
      } else {
        sumMissingSection.style.display = 'none';
        sumMissingList.innerHTML = '';
      }
    }
  }

    // =========================================================================
  // SECTION H: SECTION PROGRESS & BADGES
  // =========================================================================
  function updateSectionProgress(){
    // Section 1: Appointment & Client Information
    const s1Complete = fieldText('date') && fieldText('teamMember') && fieldText('clientName');
    updateBadge('appointmentBadge', s1Complete ? 'complete' : 'incomplete');

    // Section 2: Expression of Interest
    const includeEOI = isChecked('includeEOI');
    if (!includeEOI) {
      updateBadge('eoiBadge', 'not-required');
    } else {
      const s2Complete = eoiSaleAddressValue() && (eoiValue('eoiClient1Name','clientName')) && (fieldText('eoiDate') || fieldText('date')) && (eoiValue('eoiStaffMember','teamMember'));
      updateBadge('eoiBadge', s2Complete ? 'complete' : 'incomplete');
    }

    // Section 3: Irrevocable Authority
    const includeIA = isChecked('includeIA');
    if (!includeIA) {
      updateBadge('iaBadge', 'not-required');
    } else {
      const c1Name = fieldText('clientName');
      const c2Name = fieldText('client2Name');
      const defaultIaNames = (c1Name && c2Name && !c1Name.toLowerCase().includes(c2Name.toLowerCase())) ? `${c1Name} & ${c2Name}` : (c1Name || c2Name);
      const showIaOverrides = isChecked('showIaOverrides');
      const resolvedIaNames = showIaOverrides ? (fieldText('iaClientNames') || defaultIaNames) : defaultIaNames;
      const resolvedIaAddress = showIaOverrides ? (fieldText('iaAddress') || fieldText('clientAddress')) : fieldText('clientAddress');
      const resolvedIaProperty = showIaOverrides ? (fieldText('iaProperty') || fieldText('propertySaleAddress')) : fieldText('propertySaleAddress');

      const s3Complete = resolvedIaNames && resolvedIaAddress && resolvedIaProperty;
      updateBadge('iaBadge', s3Complete ? 'complete' : 'incomplete');
    }

    // Section 4: Client ID Documents
    const hasC2 = hasClient2();
    const _hasC1Photo = hasC1Photo();
    const _hasC2Photo = hasC2Photo();
    let s4Complete = false;
    if (hasC2) {
      s4Complete = _hasC1Photo && _hasC2Photo;
    } else {
      s4Complete = _hasC1Photo;
    }
    updateBadge('photoBadge', s4Complete ? 'complete' : 'incomplete');

    // Section 5: Signatures & Completion
    let s5Complete = false;
    if (hasC2) {
      s5Complete = hasSignature && hasSignature2;
    } else {
      s5Complete = hasSignature;
    }
    updateBadge('signatureBadge', s5Complete ? 'complete' : 'incomplete');
  }

  function updateBadge(id, state){
    const badge = $(id);
    if (!badge) return;
    if (state === 'complete') {
      badge.textContent = '✓ Complete';
      badge.className = 'badge badge-complete';
    } else if (state === 'incomplete') {
      badge.textContent = '⚠ Incomplete';
      badge.className = 'badge badge-incomplete';
    } else {
      badge.textContent = 'Not Required';
      badge.className = 'badge badge-not-required';
    }
  }

    // =========================================================================
  // SECTION I: SIGNATURE CANVAS & STATUS
  // =========================================================================
  function updateSignatureStatuses() {
    // Sig 1 Status
    const sig1 = $('sig1Status');
    if (sig1) {
      if (hasSignature) {
        sig1.textContent = '✓ Captured';
        sig1.className = 'status-badge status-captured';
      } else {
        sig1.textContent = 'Required';
        sig1.className = 'status-badge status-required';
      }
    }

    // Sig 2 Status
    const sig2 = $('sig2Status');
    if (sig2) {
      const hasC2 = hasClient2();
      if (hasSignature2) {
        sig2.textContent = '✓ Captured';
        sig2.className = 'status-badge status-captured';
      } else {
        if (hasC2) {
          sig2.textContent = 'Required';
          sig2.className = 'status-badge status-required';
        } else {
          sig2.textContent = 'Optional';
          sig2.className = 'status-badge status-optional';
        }
      }
    }
  }

  function readAsDataURL(file){
    return new Promise((resolve,reject)=>{ const r=new FileReader(); r.onload=()=>resolve(r.result); r.onerror=reject; r.readAsDataURL(file); });
  }
    // =========================================================================
  // SECTION J: IMAGE LOADING & LOGO HELPERS
  // =========================================================================
  function loadImage(src){
    return new Promise((resolve,reject)=>{ const img=new Image(); img.onload=()=>resolve(img); img.onerror=reject; img.src=src; });
  }
  async function ensurePageLogo(){
    if(!pageLogoImage){
      pageLogoImage = await loadImage(LOGO_PATH);
    }
    return pageLogoImage;
  }
  // Draw a small company logo at the top-right of non-IA-template PDF pages.
  function drawSmallPageLogo(ctx){
    if(!pageLogoImage) return;
    const logoW = pageLogoImage.width;
    const logoH = pageLogoImage.height;
    const maxH = 26;  // small and professional
    const scale = Math.min(1, maxH / logoH);
    const drawW = logoW * scale;
    const drawH = logoH * scale;
    const x = 590 - drawW - 5;  // right-aligned with 5px margin
    const y = 8;                 // near the top
    ctx.drawImage(pageLogoImage, x, y, drawW, drawH);
  }
  async function ensureIAImage(city){
    if(!city) return null;
    if(iaImageCache[city]) return iaImageCache[city];
    if(!iaImageSources[city]) throw new Error('Unknown IA form: ' + city);
    status('Loading Irrevocable Authority form...');
    iaImageCache[city] = await loadImage(iaImageSources[city]);
    return iaImageCache[city];
  }
  async function ensureLaVidaImages(){
    for(let i=0;i<laVidaImageSources.length;i++){
      if(!laVidaImageCache[i]){
        status('Loading La Vida Homes EOI template...');
        laVidaImageCache[i] = await loadImage(laVidaImageSources[i]);
      }
    }
    return laVidaImageCache;
  }
  async function ensureZoomFirstConsultImages(city){
    city = city || 'perth';
    var sources = zoomFirstConsultSources[city];
    if(!sources) throw new Error('Unknown First Consult city: ' + city);
    if(!zoomFirstConsultCache[city]) zoomFirstConsultCache[city] = [];
    for(var i=0;i<sources.length;i++){
      if(!zoomFirstConsultCache[city][i]){
        zoomFirstConsultCache[city][i] = await loadImage(sources[i]);
      }
    }
    return zoomFirstConsultCache[city];
  }
  async function ensureZoomClientReviewImages(){
    for(var i=0;i<zoomClientReviewSources.length;i++){
      if(!zoomClientReviewCache[i]){
        zoomClientReviewCache[i] = await loadImage(zoomClientReviewSources[i]);
      }
    }
    return zoomClientReviewCache;
  }
  async function handlePhoto(idx,file){
    if(!file) return;
    if(!file.type.startsWith('image/')){ toast('Please choose an image file.'); return; }
    status(`Loading ${file.name}...`);
    try{
      const dataURL = await readAsDataURL(file);
      const img = await loadImage(dataURL);
      photos[idx] = { ...photos[idx], file, dataURL, img, rotation:0, name:file.name };
      renderPhotoBox(idx);
      clearGenerated();
      status('Photo loaded.');
    }catch(err){ console.error(err); toast('Could not load that photo.'); status('Ready.'); }
  }
  function renderPhotoBox(idx){
    const p=photos[idx]; const box=$(`photoBox${idx}`); const prev=$(`photoPreview${idx}`);
    if(p.img){
      box.classList.add('hasImage');
      prev.innerHTML='';
      const canvas=document.createElement('canvas'); canvas.width=520; canvas.height=300; canvas.style.maxWidth='100%'; canvas.style.borderRadius='10px';
      const ctx=canvas.getContext('2d'); ctx.fillStyle='#fff'; ctx.fillRect(0,0,canvas.width,canvas.height); drawImageContain(ctx,p.img,0,0,canvas.width,canvas.height,p.rotation);
      prev.appendChild(canvas);
    }else{
      box.classList.remove('hasImage');
      prev.innerHTML='<div><div style="font-size:32px;color:var(--gold);font-weight:900">＋</div><div>' + (idx < 4 ? 'Tap to attach photo' : 'Upload / Take Photo') + '</div></div>';
      const input = $(`photoInput${idx}`);
      if (input) input.value='';
    }
  }
  function rotatePhoto(idx){ if(!photos[idx].img) return; photos[idx].rotation=(photos[idx].rotation+90)%360; renderPhotoBox(idx); clearGenerated(); }
  function removePhoto(idx){
    if(photos[idx].img && !confirm('Are you sure you want to remove this photo?')) return;
    if(idx < 4) {
      photos[idx]={label:photoLabels[idx], file:null, dataURL:null, img:null, rotation:0, name:''};
    } else {
      const p = photos[idx];
      photos[idx]={label: p.label, client: p.client, description: p.description, isAdditional: true, file:null, dataURL:null, img:null, rotation:0, name:''};
    }
    renderPhotoBox(idx);
    clearGenerated();
  }

  // Signature pad
  const sig=$('signature'); const sctx=sig.getContext('2d'); let drawing=false;
  function clearSig(){
    if(hasSignature && !confirm('Are you sure you want to clear Signature 1?')) return;
    sctx.clearRect(0,0,sig.width,sig.height);
    hasSignature=false;
    clearGenerated();
  }
  function pos(e){ const r=sig.getBoundingClientRect(); return {x:(e.clientX-r.left)*sig.width/r.width, y:(e.clientY-r.top)*sig.height/r.height}; }
  sig.addEventListener('pointerdown', e=>{ e.preventDefault(); drawing=true; hasSignature=true; const p=pos(e); sctx.beginPath(); sctx.moveTo(p.x,p.y); sctx.lineWidth=4; sctx.lineCap='round'; sctx.lineJoin='round'; sctx.strokeStyle='#111'; sig.setPointerCapture(e.pointerId); clearGenerated(); });
  sig.addEventListener('pointermove', e=>{ if(!drawing) return; e.preventDefault(); const p=pos(e); sctx.lineTo(p.x,p.y); sctx.stroke(); });
  sig.addEventListener('pointerup', e=>{ drawing=false; clearGenerated(); try{sig.releasePointerCapture(e.pointerId)}catch{} });
  sig.addEventListener('pointercancel', ()=>drawing=false);
  $('clearSignature').addEventListener('click', clearSig);

  const sig2=$('signature2'); const sctx2=sig2.getContext('2d'); let drawing2=false;
  function clearSig2(){
    if(hasSignature2 && !confirm('Are you sure you want to clear Signature 2?')) return;
    sctx2.clearRect(0,0,sig2.width,sig2.height);
    hasSignature2=false;
    clearGenerated();
  }
  function pos2(e){ const r=sig2.getBoundingClientRect(); return {x:(e.clientX-r.left)*sig2.width/r.width, y:(e.clientY-r.top)*sig2.height/r.height}; }
  sig2.addEventListener('pointerdown', e=>{ e.preventDefault(); drawing2=true; hasSignature2=true; const p=pos2(e); sctx2.beginPath(); sctx2.moveTo(p.x,p.y); sctx2.lineWidth=4; sctx2.lineCap='round'; sctx2.lineJoin='round'; sctx2.strokeStyle='#111'; sig2.setPointerCapture(e.pointerId); clearGenerated(); });
  sig2.addEventListener('pointermove', e=>{ if(!drawing2) return; e.preventDefault(); const p=pos2(e); sctx2.lineTo(p.x,p.y); sctx2.stroke(); });
  sig2.addEventListener('pointerup', e=>{ drawing2=false; clearGenerated(); try{sig2.releasePointerCapture(e.pointerId)}catch{} });
  sig2.addEventListener('pointercancel', ()=>drawing2=false);
  $('clearSignature2').addEventListener('click', clearSig2);

    // =========================================================================
  // SECTION K: PDF DRAWING PRIMITIVES
  // =========================================================================
  function drawRoundRect(ctx,x,y,w,h,r,fill,stroke){
    ctx.beginPath(); ctx.moveTo(x+r,y); ctx.lineTo(x+w-r,y); ctx.quadraticCurveTo(x+w,y,x+w,y+r); ctx.lineTo(x+w,y+h-r); ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h); ctx.lineTo(x+r,y+h); ctx.quadraticCurveTo(x,y+h,x,y+h-r); ctx.lineTo(x,y+r); ctx.quadraticCurveTo(x,y,x+r,y); ctx.closePath();
    if(fill) ctx.fill(); if(stroke) ctx.stroke();
  }
  function wrapText(ctx,text,x,y,maxWidth,lineHeight,maxLines){
    text=(text||'').toString();
    const words=text.replace(/\n/g,' \n ').split(/\s+/); let line=''; let lines=0;
    for(let i=0;i<words.length;i++){
      const word=words[i];
      if(word==='\n') { ctx.fillText(line,x,y); y+=lineHeight; line=''; lines++; if(maxLines&&lines>=maxLines)return y; continue; }
      if(ctx.measureText(word).width>maxWidth){
        if(line){ ctx.fillText(line,x,y); y+=lineHeight; lines++; line=''; if(maxLines&&lines>=maxLines)return y; }
        let chunk='';
        for(const ch of word){
          const test=chunk+ch;
          if(ctx.measureText(test).width>maxWidth && chunk){ ctx.fillText(chunk,x,y); y+=lineHeight; lines++; chunk=ch; if(maxLines&&lines>=maxLines)return y; }
          else chunk=test;
        }
        line=chunk;
        continue;
      }
      const test=line ? line+' '+word : word;
      if(ctx.measureText(test).width>maxWidth && line){ ctx.fillText(line,x,y); y+=lineHeight; line=word; lines++; if(maxLines&&lines>=maxLines)return y; }
      else line=test;
    }
    if(line && (!maxLines || lines<maxLines)){ ctx.fillText(line,x,y); y+=lineHeight; }
    return y;
  }
  function formatISODate(value) {
    if (!value) return '';
    const str = String(value).trim();
    const validISO = (yyyy, mm, dd) => {
      const y = Number(yyyy), m = Number(mm), d = Number(dd);
      const parsed = new Date(y, m - 1, d);
      if(parsed.getFullYear() !== y || parsed.getMonth() !== m - 1 || parsed.getDate() !== d) return '';
      return `${String(y).padStart(4, '0')}-${String(m).padStart(2, '0')}-${String(d).padStart(2, '0')}`;
    };
    const dmyMatch = str.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
    if (dmyMatch) {
      return validISO(dmyMatch[3], dmyMatch[2], dmyMatch[1]);
    }
    const ymdMatch = str.match(/^(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})$/);
    if (ymdMatch) {
      return validISO(ymdMatch[1], ymdMatch[2], ymdMatch[3]);
    }
    try {
      const parsed = new Date(value);
      if (!isNaN(parsed.getTime())) {
        const dd = String(parsed.getDate()).padStart(2, '0');
        const mm = String(parsed.getMonth() + 1).padStart(2, '0');
        const yyyy = parsed.getFullYear();
        return `${yyyy}-${mm}-${dd}`;
      }
    } catch (e) {}
    return '';
  }
  function fieldText(id){ return ($(id).value || '').trim(); }
  function formatDisplayDate(value){
    if(!value) return '';
    const str = String(value).trim();
    if(/^\d{2}\/\d{2}\/\d{4}$/.test(str)) return str;
    if(/^\d{4}-\d{2}-\d{2}$/.test(str)){
      const parts = str.split('-');
      return `${parts[2]}/${parts[1]}/${parts[0]}`;
    }
    if(/^\d{2}-\d{2}-\d{4}$/.test(str)){
      return str.replace(/-/g, '/');
    }
    if(value instanceof Date && !isNaN(value)){
      const dd = String(value.getDate()).padStart(2, '0');
      const mm = String(value.getMonth() + 1).padStart(2, '0');
      const yyyy = value.getFullYear();
      return `${dd}/${mm}/${yyyy}`;
    }
    try {
      const parsed = new Date(value);
      if(!isNaN(parsed.getTime())){
        const dd = String(parsed.getDate()).padStart(2, '0');
        const mm = String(parsed.getMonth() + 1).padStart(2, '0');
        const yyyy = parsed.getFullYear();
        return `${dd}/${mm}/${yyyy}`;
      }
    } catch(e){}
    return value;
  }
  function formatDisplayDateTime(value){
    const date = value instanceof Date ? value : new Date(value);
    if(isNaN(date.getTime())) return '';
    const d = new Date(date);
    const dd = String(d.getDate()).padStart(2, '0');
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const yyyy = d.getFullYear();
    const hh = String(d.getHours()).padStart(2, '0');
    const min = String(d.getMinutes()).padStart(2, '0');
    return `${dd}/${mm}/${yyyy} ${hh}:${min}`;
  }
