  function formatPrice(val){
    val = (val || '').trim();
    if(!val) return '';
    // Strip any existing $ and commas, then reformat as currency.
    const num = parseFloat(val.replace(/[^0-9.]/g, ''));
    if(!isNaN(num) && num > 0){
      return '$' + num.toLocaleString('en-US');
    }
    // If the user already has a $ prefix or partial entry, return as-is.
    return val;
  }

  // Strip currency formatting back to a plain number string for editing.
  function stripCurrency(val){
    return (val || '').replace(/[^\d.]/g, '');
  }

  let lastLand = '';
  let lastHouse = '';
  function updateHLTotal(){
    const landEl = $('eoiPriceLand');
    const houseEl = $('eoiPriceHouse');
    const totalEl = $('eoiPriceTotal');
    if (!landEl || !houseEl || !totalEl) return;
    const landVal = stripCurrency(landEl.value);
    const houseVal = stripCurrency(houseEl.value);
    if (landVal !== lastLand || houseVal !== lastHouse) {
      lastLand = landVal;
      lastHouse = houseVal;
      const landNum = parseFloat(landVal) || 0;
      const houseNum = parseFloat(houseVal) || 0;
      if (landVal.trim() || houseVal.trim()) {
        const sum = landNum + houseNum;
        totalEl.value = sum > 0 ? '$' + sum.toLocaleString('en-US') : '';
        clearGenerated();
      } else {
        totalEl.value = '';
        clearGenerated();
      }
    }
  }

