  function drawLineValue(ctx,label,value,x,y,w,opts={}){
    const labelW = opts.labelW || 95;
    const lineH = opts.lineH || 24;
    const maxLines = opts.maxLines || 1;
    ctx.fillStyle='#172033'; ctx.font='700 10.5px Arial'; ctx.fillText(label,x,y);

    // Draw underlines
    ctx.strokeStyle='#cfd3df'; ctx.lineWidth=1;
    ctx.beginPath();
    for (let i = 0; i < maxLines; i++) {
      const lineY = y + 3 + i * lineH;
      ctx.moveTo(x+labelW, lineY);
      ctx.lineTo(x+w, lineY);
    }
    ctx.stroke();

    ctx.fillStyle=value?'#172033':'#9aa0af';
    const valueX = x + labelW + 5;
    const valueW = w - labelW - 8;
    if(value && maxLines === 1 && opts.fit !== false){
      let size = opts.fontSize || 11.5;
      const weight = opts.fontWeight || '400';
      while(size > 8){
        ctx.font = `${weight} ${size}px Arial`;
        if(ctx.measureText(value).width <= valueW) break;
        size -= 0.5;
      }
      if(ctx.measureText(value).width <= valueW) ctx.fillText(value, valueX, y - 0.5);
      else wrapText(ctx,value,valueX,y-0.5,valueW,lineH,1);
    } else {
      ctx.font=opts.font || '11.5px Arial';
      wrapText(ctx,value || '',valueX,y-0.5,valueW,lineH,maxLines);
    }
  }
  function drawImageContain(ctx,img,x,y,w,h,rotation){
    ctx.save();
    ctx.beginPath(); ctx.rect(x,y,w,h); ctx.clip();
    ctx.fillStyle='#fff'; ctx.fillRect(x,y,w,h);
    const rot = ((rotation||0)%360+360)%360;
    const boundingW = rot===90 || rot===270 ? img.height : img.width;
    const boundingH = rot===90 || rot===270 ? img.width : img.height;
    const scale = Math.min(w/boundingW, h/boundingH);
    const drawW = img.width*scale, drawH = img.height*scale;
    ctx.translate(x+w/2,y+h/2); ctx.rotate(rot*Math.PI/180);
    ctx.drawImage(img,-drawW/2,-drawH/2,drawW,drawH);
    ctx.restore();
  }
  function drawPhotoPage(photo, pageNumber, totalPages, scale=2){
    const W=595,H=842; const c=document.createElement('canvas'); c.width=Math.round(W*scale); c.height=Math.round(H*scale); const ctx=c.getContext('2d'); ctx.scale(scale,scale);
    const photoIdx = photos.indexOf(photo);
    let clientNameForSub = '';
    if (photo.isAdditional) {
      if (photo.client === 'Client 2') {
        clientNameForSub = fieldText('client2Name') || 'Client 2';
      } else {
        clientNameForSub = fieldText('clientName') || 'Client 1';
      }
    } else {
      clientNameForSub = (photoIdx >= 2)
        ? (fieldText('client2Name') || fieldText('clientName') || 'Client 2')
        : (fieldText('clientName') || 'Client');
    }
    const pageTitle = photo.isAdditional ? `${photo.client || 'Client 1'} – ${photo.description || 'Additional Document'}` : photo.label;
    drawPageFrame(ctx, pageTitle, `${clientNameForSub} | ${formatDisplayDate(fieldText('date')) || 'Date'} | ${photo.name || 'Attached photo'}`, pageNumber, totalPages);
    const contentX=42, contentY=100, contentW=511, contentH=680;
    const pad=12;
    const rot = ((photo.rotation||0)%360+360)%360;
    const imgW = rot===90 || rot===270 ? photo.img.height : photo.img.width;
    const imgH = rot===90 || rot===270 ? photo.img.width : photo.img.height;
    const fit = Math.min((contentW-pad*2)/imgW, (contentH-pad*2)/imgH);
    const drawW = imgW * fit;
    const drawH = imgH * fit;
    const frameW = Math.min(contentW, drawW + pad*2);
    const frameH = Math.min(contentH, drawH + pad*2);
    const frameX = contentX + (contentW - frameW) / 2;
    const frameY = contentY + (contentH - frameH) / 2;
    ctx.strokeStyle='#e7e7ef'; ctx.fillStyle='#fbfbfe'; ctx.lineWidth=1.5; drawRoundRect(ctx,frameX,frameY,frameW,frameH,10,true,true);
    drawImageContain(ctx,photo.img,frameX+pad,frameY+pad,frameW-pad*2,frameH-pad*2,photo.rotation);
    return c;
  }

