  // SECTION L: IA TEMPLATE PAGE DRAWING
  // =========================================================================
  function drawIAPage(city, pageNumber, totalPages, scale=2){
    const img = iaImageCache[city];
    if(!img) throw new Error('IA form image has not loaded.');
    const W=595,H=842; const c=document.createElement('canvas'); c.width=Math.round(W*scale); c.height=Math.round(H*scale); const ctx=c.getContext('2d'); ctx.scale(scale,scale);
    ctx.fillStyle='#fff'; ctx.fillRect(0,0,W,H);

    // The source IA PDFs are US Letter ratio. Fit them onto the generated PDF page without distortion.
    const imgAspect = img.width / img.height;
    const pageAspect = W / H;
    let dw, dh, dx, dy;
    if(imgAspect > pageAspect){ dw = W; dh = W / imgAspect; dx = 0; dy = (H - dh) / 2; }
    else { dh = H; dw = H * imgAspect; dx = (W - dw) / 2; dy = 0; }
    ctx.drawImage(img, dx, dy, dw, dh);

    const map = (sx, sy) => ({ x: dx + (sx / img.width) * dw, y: dy + (sy / img.height) * dh });
    const maxW = sw => (sw / img.width) * dw;
    function whiteOut(sx, sy, sw, sh){
      const p1 = map(sx, sy); const p2 = map(sx + sw, sy + sh);
      ctx.fillStyle = '#fff';
      ctx.fillRect(p1.x, p1.y, p2.x - p1.x, p2.y - p1.y);
    }
    function overlayText(text, sx, sy, sw, font='700 12px Arial', lineHeight=14, maxLines=2){
      text = (text || '').trim();
      if(!text) return;
      const p = map(sx, sy);
      ctx.fillStyle = '#111';
      ctx.font = font;
      wrapText(ctx, text, p.x, p.y, maxW(sw), lineHeight, maxLines);
    }
    function overlayFitText(text, sx, sy, sw, weight='700', maxSize=12, minSize=8){
      text = (text || '').trim();
      if(!text) return;
      const p = map(sx, sy);
      const width = maxW(sw);
      let size = maxSize;
      ctx.fillStyle = '#111';
      while(size > minSize){
        ctx.font = `${weight} ${size}px Arial`;
        if(ctx.measureText(text).width <= width) break;
        size -= 0.5;
      }
      ctx.font = `${weight} ${size}px Arial`;
      if(ctx.measureText(text).width <= width){
        ctx.fillText(text, p.x, p.y);
      } else {
        wrapText(ctx, text, p.x, p.y, width, size + 2, 2);
      }
    }
    function drawTemplateLineValue(text, sx, baselineSy, sw, options={}){
      text = (text || '').trim();
      if(!text) return;
      const p = map(sx, baselineSy);
      const padLeft = options.padLeft ?? 8;
      const padRight = options.padRight ?? 12;
      const width = Math.max(20, maxW(sw) - padLeft - padRight);
      const weight = options.weight || '700';
      const maxSize = options.maxSize || 10.5;
      const minSize = options.minSize || 8.5;
      const maxLines = options.maxLines || 2;

      function linesForSize(size){
        ctx.font = `${weight} ${size}px Arial`;
        const words = text.replace(/\n/g, ' \n ').split(/\s+/).filter(Boolean);
        const lines = [];
        let line = '';
        function pushLine(value){
          if(value) lines.push(value);
        }
        for(const word of words){
          if(word === '\n'){
            pushLine(line);
            line = '';
            continue;
          }
          const candidate = line ? `${line} ${word}` : word;
          if(ctx.measureText(candidate).width <= width){
            line = candidate;
            continue;
          }
          pushLine(line);
          line = '';
          if(ctx.measureText(word).width <= width){
            line = word;
            continue;
          }
          let chunk = '';
          for(const ch of word){
            const test = chunk + ch;
            if(ctx.measureText(test).width > width && chunk){
              pushLine(chunk);
              chunk = ch;
            } else {
              chunk = test;
            }
          }
          line = chunk;
        }
        pushLine(line);
        return lines;
      }

      let size = maxSize;
      let lines = [];
      const lineGap = options.lineGap ?? 2;
      let lineHeight = size + lineGap;
      while(size >= minSize){
        lines = linesForSize(size);
        if(lines.length <= maxLines) break;
        size -= 0.5;
      }
      size = Math.max(size, minSize);
      ctx.font = `${weight} ${size}px Arial`;
      const fittedLines = linesForSize(size);
      const didTruncate = fittedLines.length > maxLines;
      lines = fittedLines.slice(0, maxLines);
      if(lines.length){
        const lastIndex = lines.length - 1;
        if(didTruncate && !lines[lastIndex].endsWith('...')) lines[lastIndex] = `${lines[lastIndex]}...`;
        while(ctx.measureText(lines[lastIndex]).width > width && lines[lastIndex].length > 1){
          lines[lastIndex] = `${lines[lastIndex].slice(0, -2)}...`;
        }
      }
      lineHeight = size + lineGap;
      const previousBaseline = ctx.textBaseline;
      ctx.fillStyle = '#111';
      ctx.textBaseline = 'alphabetic';
      lines.forEach((line, index) => {
        ctx.fillText(line, p.x + padLeft, p.y + (index * lineHeight));
      });
      ctx.textBaseline = previousBaseline;
    }

    const client1 = fieldText('clientName');
    const client2 = fieldText('client2Name');
    const defaultIaNames = (client1 && client2 && !client1.toLowerCase().includes(client2.toLowerCase()))
      ? `${client1} & ${client2}`
      : (client1 || client2);
    const defaultIaAddress = fieldText('clientAddress');
    const defaultIaProperty = fieldText('propertySaleAddress');

    const showOverrides = isChecked('showIaOverrides');
    const iaClientNames = showOverrides ? (fieldText('iaClientNames') || defaultIaNames) : defaultIaNames;
    const iaAddress = showOverrides ? (fieldText('iaAddress') || defaultIaAddress) : defaultIaAddress;
    const iaProperty = showOverrides ? (fieldText('iaProperty') || defaultIaProperty) : defaultIaProperty;
    const iaAmount = fieldText('iaAmount') || '$10,000';

    whiteOut(315, 312, 850, 32);
    whiteOut(245, 360, 900, 32);
    // Property field — whiteout ends well above the black IRREVOCABLE AUTHORITY banner.
    // Keep height tight so no white fill intrudes on the banner below.
    whiteOut(300, 405, 850, 26);
    // TO: line — white-out only the dynamic value area after the printed
    // "TO: Solicitor/Conveyancer:" label so the label itself stays visible.
    whiteOut(630, 535, 885, 45);
    whiteOut(758, 752, 152, 44);
    whiteOut(225, 1206, 401, 36);
    drawTemplateLineValue(iaClientNames, 315, 330, 850, {maxLines: 2, maxSize: 10, minSize: 8, padLeft: 8, padRight: 16});
    drawTemplateLineValue(iaAddress, 245, 378, 900, {maxLines: 2, maxSize: 9.5, minSize: 8, padLeft: 8, padRight: 16});
    // Single line with aggressive shrinkage to keep text above the black banner.
    drawTemplateLineValue(iaProperty, 300, 420, 850, {maxLines: 1, maxSize: 9.5, minSize: 7, padLeft: 8, padRight: 16, lineGap: 1});
    overlayFitText(fieldText('iaSolicitor'), 640, 564, 875, '400', 12, 6);
    overlayText(iaAmount, 763, 783, 140, '800 13px Arial', 15, 1);
    overlayText(formattedDateForIA(), 235, 1225, 391, '700 12px Arial', 14, 1);

    if(hasSignature && $('iaApplySignature1') && $('iaApplySignature1').checked){
      const p1 = map(130, 1364);
      const p2 = map(570, 1458);
      ctx.drawImage(sig, p1.x, p1.y, p2.x - p1.x, p2.y - p1.y);
    }
    if(hasSignature2 && $('iaApplySignature2') && $('iaApplySignature2').checked){
      const p1 = map(700, 1364);
      const p2 = map(1140, 1458);
      ctx.drawImage(sig2, p1.x, p1.y, p2.x - p1.x, p2.y - p1.y);
    }

    ctx.fillStyle='rgba(255,255,255,.94)';
    ctx.fillRect(38,806,519,28);
    drawGeneratedFooter(ctx,pageNumber,totalPages,'Irrevocable Authority',42,817);

    return c;
  }

