  function getDraft(){
    const data={}; fields.forEach(id=>{const el=$(id); if(!el)return; data[id]=(el.type==='checkbox')?el.checked:el.value;});
    data.eoiOwnership=eoiOwnership();
    data.signature=hasSignature?sig.toDataURL('image/png'):null;
    data.signature2=hasSignature2?sig2.toDataURL('image/png'):null;
    data.additionalDocsCount = Math.max(0, photos.length - 4);
    data.photos=photos.map(p=>({label:p.label,dataURL:p.dataURL,rotation:p.rotation,name:p.name,client:p.client,description:p.description,isAdditional:p.isAdditional}));
    data.eoiNextAppointment=formatNextAppointment();
    data.eoiIdAttached='';
    data.appointmentMode = appointmentMode;
    return data;
  }
  async function setDraft(data){
    if(!data) return;
    if (data.includeIA === undefined) {
      if (data.iaTemplate || (data.iaForm && data.iaForm !== '')) {
        data.includeIA = true;
      } else {
        data.includeIA = false;
      }
    }
    if (data.iaTemplate && !data.iaForm) {
      data.iaForm = data.iaTemplate;
    }
    if (data.includeEOI !== undefined) {
      data.includeEOI = !!data.includeEOI;
    }
    if (data.eoiTemplate === undefined || !String(data.eoiTemplate).trim()) {
      data.eoiTemplate = 'standard';
    }
    migrateLaVidaDraftSelections(data);
    preserveDraftDropdownValue('staff', data.teamMember);
    preserveDraftDropdownValue('staff', data.eoiStaffMember);
    preserveDraftDropdownValue('branch', data.eoiBranch);
    preserveDraftDropdownValue('solicitor', data.iaSolicitor);
    preserveDraftDropdownValue('eoiTemplates', data.eoiTemplate);
    /* Preserve zoom dropdown values from draft */
    renderZoomFields();
    preserveZoomDraftValue('clientReviewBuilder', data.clientReviewBuilder);
    preserveZoomDraftValue('clientReviewDeveloper', data.clientReviewDeveloper);
    preserveZoomDraftValue('clientReviewBroker', data.clientReviewBroker);
    preserveZoomDraftValue('clientReviewConveyancer', data.clientReviewConveyancer);
    preserveZoomDraftValue('clientReviewTimeline', data.clientReviewTimeline);
    renderAdminSettings();
    renderConfigurableFields();
    fields.forEach(id=>{
      const el=$(id);
      if(!el || data[id]===undefined)return;
      if(el.type==='checkbox') el.checked=!!data[id];
      else {
        if(id==='eoiNextApptDate'){
          el.value = formatISODate(data[id]) || '';
        } else if(id==='date' || id==='iaDate' || id==='eoiDate'){
          el.value = formatDisplayDate(data[id]);
        } else {
          el.value = data[id];
        }
      }
    });
    if ((data.eoiNextApptDate === undefined || !String(data.eoiNextApptDate).trim()) && data.eoiNextAppointment) {
      const val = String(data.eoiNextAppointment).trim();
      const dateMatch = val.match(/(\d{1,2}[\/\-]\d{1,2}[\/\-]\d{4})/);
      if (dateMatch && $('eoiNextApptDate')) {
        $('eoiNextApptDate').value = formatISODate(dateMatch[1]) || '';
      }
      const timeMatch = val.match(/(\d{1,2}:\d{2}\s*(?:AM|PM|am|pm))/i);
      if (timeMatch && $('eoiNextApptTime')) {
        let t = timeMatch[1].toUpperCase().trim();
        if (/^\d{1,2}:\d{2}(?:AM|PM)$/.test(t)) {
          t = t.slice(0, -2) + ' ' + t.slice(-2);
        }
        $('eoiNextApptTime').value = t;
      }
    }
    if((data.eoiSaleAddress === undefined || !String(data.eoiSaleAddress).trim()) && data.iaProperty && $('eoiSaleAddress')) $('eoiSaleAddress').value = data.iaProperty;
    if(data.eoiOwnership){
      const ownershipEl=document.querySelector(`input[name="eoiOwnership"][value="${data.eoiOwnership}"]`);
      if(ownershipEl) ownershipEl.checked=true;
    }
    clearSig();
    if(data.signature){ const im=await loadImage(data.signature); sctx.drawImage(im,0,0,sig.width,sig.height); hasSignature=true; }
    clearSig2();
    const signature2Data = data.signature2 || data.eoiSignature2;
    if(signature2Data){ const im2=await loadImage(signature2Data); sctx2.drawImage(im2,0,0,sig2.width,sig2.height); hasSignature2=true; }
    if(Array.isArray(data.photos) || data.additionalDocsCount !== undefined){
      const draftPhotos = Array.isArray(data.photos) ? data.photos : [];
      const explicitAdditionalCount = parseInt(data.additionalDocsCount || 0, 10);
      const addDocsCount = Math.max(0, Number.isFinite(explicitAdditionalCount) ? explicitAdditionalCount : 0, draftPhotos.length - 4);
      if ($('additionalDocsCount')) {
        $('additionalDocsCount').value = String(addDocsCount > 0 ? addDocsCount : 0);
      }
      photos.length = 4;
      if (addDocsCount > 0) {
        for(let i = 0; i < addDocsCount; i++) {
          const d = draftPhotos[4 + i];
          photos.push({
            label: d ? d.label : 'Client 1 – Additional Document',
            client: d ? (d.client || 'Client 1') : 'Client 1',
            description: d ? (d.description || '') : '',
            isAdditional: true,
            file: null,
            dataURL: null,
            img: null,
            rotation: 0,
            name: ''
          });
        }
      }
      renderAdditionalDocsUI();

      for(let i=0;i<photos.length;i++){
        const d=draftPhotos[i];
        if(d && d.dataURL){
          const im=await loadImage(d.dataURL);
          if (i < 4) {
            photos[i]={label:photoLabels[i],dataURL:d.dataURL,img:im,rotation:d.rotation||0,name:d.name||'',file:null};
          } else {
            photos[i]={
              label:d.label,
              client:d.client || 'Client 1',
              description:d.description || '',
              isAdditional:true,
              dataURL:d.dataURL,
              img:im,
              rotation:d.rotation||0,
              name:d.name||'',
              file:null
            };
          }
        }
        else {
          if (i < 4) {
            photos[i]={label:photoLabels[i],file:null,dataURL:null,img:null,rotation:0,name:''};
          } else {
            const p = photos[i];
            photos[i]={label:p.label, client:p.client, description:p.description, isAdditional:true, file:null, dataURL:null, img:null, rotation:0, name:''};
          }
        }
        renderPhotoBox(i);
      }
    }
    syncLaVidaContactsFromChoices(false);
    /* Restore appointment mode from draft */
    appointmentMode = data.appointmentMode || 'inPerson';
    $('landingScreen').classList.add('hidden');
    $('backToStart').style.display = '';
    if($('landingStaff')) $('landingStaff').value = fieldText('teamMember') || '';
    applyAppointmentMode();
    refreshAllUI();
  }
  function saveDraft(){
    try{
      var data = getDraft();
      data.draftSavedAt = new Date().toISOString();
      localStorage.setItem('salesAppointmentDraft', JSON.stringify(data));
      toast('Draft saved on this device.');
    }catch(e){
      toast('Draft could not be saved. Photos may be too large for browser storage.');
    }
  }
  async function loadDraft(){ try{ const raw=localStorage.getItem('salesAppointmentDraft'); if(!raw){toast('No saved draft found on this device.'); return;} await setDraft(JSON.parse(raw)); toast('Draft loaded.'); }catch(e){ console.error(e); toast('Draft could not be loaded.'); } }
